import (
	"sort"
	"testing"

	"github.com/iksnae/code-certification/internal/discovery"
)

func TestKnownLanguages_AllUniqueSorted(t *testing.T) {
	langs := discovery.KnownLanguages()

	// Must be non-empty
	if len(langs) == 0 {
		t.Fatal("KnownLanguages() should not be empty")
	}

	// Must be sorted
	if !sort.StringsAreSorted(langs) {
		t.Errorf("KnownLanguages() should be sorted, got %v", langs)
	}

	// Must be deduplicated (no adjacent duplicates since sorted)
	for i := 1; i < len(langs); i++ {
		if langs[i] == langs[i-1] {
			t.Errorf("KnownLanguages() contains duplicate %q", langs[i])
		}
	}

	// Verify the exact set of expected languages derived from certifiableExts.
	// This test will fail CI when a new language extension is added to
	// certifiableExts without a corresponding tier entry in the registry.
	expected := []string{
		"c", "cpp", "cs", "elixir", "erlang", "go", "java", "js",
		"kt", "lua", "php", "proto", "py", "r", "rb", "rs",
		"scala", "sh", "sql", "swift", "ts", "zig",
	}

	if len(langs) != len(expected) {
		t.Fatalf("KnownLanguages() has %d entries, want %d\ngot:  %v\nwant: %v",
			len(langs), len(expected), langs, expected)
	}

	for i, lang := range expected {
		if langs[i] != lang {
			t.Errorf("KnownLanguages()[%d] = %q, want %q", i, langs[i], lang)
		}
	}
}

