import "fmt"

// Tier represents the analysis capability tier for a programming language.
type Tier int

const (
	// TierNone indicates no analysis capability for this language.
	TierNone Tier = iota
	// TierGeneric indicates basic (line-count, presence) analysis only.
	TierGeneric
	// TierLint indicates lint-level analysis is available.
	TierLint
	// TierParse indicates parse/structural-level analysis is available.
	TierParse
	// TierFull indicates full semantic analysis is available.
	TierFull
)

var tierStrings = map[Tier]string{
	TierNone:    "None",
	TierGeneric: "Generic",
	TierLint:    "Lint",
	TierParse:   "Parse",
	TierFull:    "Full",
}

// String returns the human-readable name of the tier.
func (t Tier) String() string {
	if s, ok := tierStrings[t]; ok {
		return s
	}
	return fmt.Sprintf("Tier(%d)", t)
}

// languageTiers maps every known language ID to its analysis capability tier.
var languageTiers = map[string]Tier{
	// TierFull — languages with deep semantic analysis
	"go": TierFull,
	"ts": TierFull,
	"js": TierFull,
	"py": TierFull,
	"rs": TierFull,

	// TierGeneric — languages with basic file-level analysis
	"rb":     TierGeneric,
	"java":   TierGeneric,
	"kt":     TierGeneric,
	"sh":     TierGeneric,
	"c":      TierGeneric,
	"cpp":    TierGeneric,
	"cs":     TierGeneric,
	"swift":  TierGeneric,
	"php":    TierGeneric,
	"elixir": TierGeneric,
	"erlang": TierGeneric,
	"scala":  TierGeneric,
	"lua":    TierGeneric,
	"r":      TierGeneric,
	"zig":    TierGeneric,
	"sql":    TierGeneric,
	"proto":  TierGeneric,
}

// TierForLanguage returns the analysis capability tier for the given language ID.
// Unknown languages default to TierGeneric.
func TierForLanguage(lang string) Tier {
	if t, ok := languageTiers[lang]; ok {
		return t
	}
	return TierGeneric
}

