func TestLanguageTiersRegistry(t *testing.T) {
	// Verify we have exactly the expected number of tier entries.
	// If discovery adds a new language extension, this count must grow.
	expectedCount := 22
	if len(languageTiers) != expectedCount {
		t.Errorf("languageTiers has %d entries, expected %d. "+
			"Did you add a language extension to discovery without a tier entry?",
			len(languageTiers), expectedCount)
	}

	// Verify every discovery language name maps to a tier entry.
	// We map discovery language names to the tier IDs used in languageTiers.
	nameToTierID := map[string]string{
		"go":         "go",
		"typescript": "ts",
		"javascript": "js",
		"python":     "py",
		"rust":       "rs",
		"ruby":       "rb",
		"java":       "java",
		"kotlin":     "kt",
		"shell":      "sh",
	}

	for _, langToTierID := range nameToTierID {
		if _, ok := languageTiers[langToTierID]; !ok {
			t.Errorf("discovery language %q maps to tier ID %q which is missing from languageTiers",
				langToTierID, langToTierID)
		}
	}

	// This is the CI-gate: every language name detected by discovery
	// must have a corresponding tier entry. If someone adds a new
	// extension to discovery's extToLanguage map, this loop will
	// catch the missing tier entry.
	for langName := range discovery.ExtToLanguage {
		tierID, known := nameToTierID[langName]
		if !known {
			t.Errorf("discovery language %q has no tier ID mapping — "+
				"add it to nameToTierID in this test AND to languageTiers in language_tiers.go",
				langName)
			continue
		}
		if _, ok := languageTiers[tierID]; !ok {
			t.Errorf("discovery language %q → tier ID %q is missing from languageTiers",
				langName, tierID)
		}
	}
}

func TestTierString(t *testing.T) {
	tests := []struct {
		tier Tier
		want string
	}{
		{TierNone, "None"},
		{TierGeneric, "Generic"},
		{TierLint, "Lint"},
		{TierParse, "Parse"},
		{TierFull, "Full"},
		{Tier(99), "Tier(99)"},
	}

	for _, tt := range tests {
		got := tt.tier.String()
		if got != tt.want {
			t.Errorf("Tier(%d).String() = %q, want %q", tt.tier, got, tt.want)
		}
	}
}

